16	import { supabase } from '@/lib/supabase';
17	import type { Database } from '@/types/supabase';
18	
19	// US-048 — Lister Home/dashboard. Calls `lister_dashboard_counts` (single
20	// SECURITY INVOKER RPC returning three ints: active_campaigns,
21	// pending_applications, pending_submissions — see companion migration
22	// `us_048_lister_dashboard_counts_rpc`). Three tiles are the v1 scope per
23	// docs/product-plan.md line 124 ("Lister analytics dashboard: just counts
24	// in v1"). FAB per docs/design.md §2.3 + §3.2 routes to the campaign
25	// wizard step 1 (route lands in US-049 — the FAB is wired ahead so it
26	// starts working the instant the route file exists).
27	//
28	// Spec gap: US-048 AC names `app/(lister)/index.tsx` but the canonical
29	// route per docs/design.md §2.3 is `/(lister)/dashboard` and the file
30	// already lives at `app/(lister)/dashboard.tsx` (US-031). Specs win;
31	// overwriting the placeholder here instead of creating index.tsx.
32	
33	type CountsRow = Database['public']['Functions']['lister_dashboard_counts']['Returns'][number];
34	
35	type Tile = {
36	  key: keyof CountsRow;
37	  label: string;
38	};
39	
40	const TILES: readonly Tile[] = [
41	  { key: 'active_campaigns', label: 'Active campaigns' },
42	  { key: 'pending_applications', label: 'Pending applications' },
43	  { key: 'pending_submissions', label: 'Pending submissions' },
44	];
45	
46	const ZERO_COUNTS: CountsRow = {
47	  active_campaigns: 0,
48	  pending_applications: 0,
49	  pending_submissions: 0,
50	};
51	
52	export default function ListerDashboard() {
53	  const { user } = useAuth();
54	  const userId = user?.id ?? null;
55	
56	  const [counts, setCounts] = useState<CountsRow | null>(null);
57	  const [loading, setLoading] = useState(true);
58	  const [refreshing, setRefreshing] = useState(false);
59	  const [error, setError] = useState<string | null>(null);
60	
61	  const load = useCallback(async () => {
62	    if (!userId) return;
63	    setError(null);
64	    const { data, error: rpcError } = await supabase.rpc('lister_dashboard_counts');
65	    if (rpcError) {
66	      setError("Couldn't load dashboard stats.");
67	      setCounts(null);
68	    } else {
69	      // RPC returns `setof record` so data is an array; the function
70	      // always yields exactly one row (three scalar sub-selects joined by
71	      // comma), but fall back to zeros if the client receives an empty
72	      // payload for any reason.
73	      setCounts(data?.[0] ?? ZERO_COUNTS);
74	    }
75	  }, [userId]);
76	
77	  useEffect(() => {
78	    setLoading(true);
79	    void load().finally(() => setLoading(false));
80	  }, [load]);
81	
82	  const onRefresh = useCallback(async () => {
83	    setRefreshing(true);
84	    await load();
85	    setRefreshing(false);
86	  }, [load]);
87	
88	  const onCreate = useCallback(() => {
89	    router.push('/(lister)/campaigns/new/step-1');
90	  }, []);
91	
92	  return (
93	    <SafeAreaView style={styles.root}>
94	      <ScrollView
95	        contentContainerStyle={styles.scroll}
96	        refreshControl={
97	          <RefreshControl refreshing={refreshing} onRefresh={onRefresh} tintColor={colors.ink} />
98	        }
99	      >
100	        <Text style={[textStyles.display, styles.header]}>Home</Text>
101	
102	        {loading ? (
103	          <View style={styles.tileList} testID="dashboard-loading">
104	            <SkeletonCard height={96} />
105	            <SkeletonCard height={96} />
106	            <SkeletonCard height={96} />
107	          </View>
108	        ) : error ? (
109	          <View style={styles.errorBox}>
110	            <Text style={[textStyles.body, { color: colors.danger }]}>{error}</Text>
111	          </View>
112	        ) : (
113	          <View style={styles.tileList}>
114	            {TILES.map((tile) => (
115	              <StatTile
116	                key={tile.key}
117	                label={tile.label}
118	                value={counts?.[tile.key] ?? 0}
119	                testID={`stat-${tile.key}`}
120	              />
121	            ))}
122	          </View>
123	        )}
124	      </ScrollView>
125	      <Fab
126	        onPress={onCreate}
127	        accessibilityLabel="Create campaign"
128	        testID="lister-fab-create"
129	      />
130	    </SafeAreaView>
131	  );
132	}
133	
134	type StatTileProps = {
135	  label: string;
136	  value: number;
137	  testID?: string;
138	};
139	
140	function StatTile({ label, value, testID }: StatTileProps) {
141	  return (
142	    <View
143	      style={[styles.tile, shadows.hard]}
144	      accessibilityRole="text"
145	      accessibilityLabel={`${label}: ${value}`}
146	      testID={testID}
147	    >
148	      <Text style={[textStyles.display, styles.tileValue]} allowFontScaling={false}>
149	        {value}
150	      </Text>
151	      <Text style={[textStyles.caption, styles.tileLabel]}>{label}</Text>
152	    </View>
153	  );
154	}
155	
156	const styles = StyleSheet.create({
157	  root: { flex: 1, backgroundColor: colors.canvas },
158	  scroll: {
159	    padding: spacing.base,
160	    gap: spacing.md,
161	    paddingBottom: spacing.xxxl,
162	  },
163	  header: {
164	    color: colors.ink,
165	    marginBottom: spacing.xs,
166	  },
167	  tileList: {
168	    gap: spacing.md,
169	  },
170	  tile: {
171	    backgroundColor: colors.surface,
172	    borderColor: colors.ink,
173	    borderWidth: 2,
174	    borderRadius: radii.card,
175	    padding: spacing.base,
176	    gap: spacing.xs,
177	  },
178	  tileValue: {
179	    color: colors.ink,
180	  },
181	  tileLabel: {
182	    color: colors.ink70,
183	  },
184	  errorBox: {
185	    padding: spacing.lg,
186	    alignItems: 'center',
187	  },
188	});
