1	import { useCallback } from 'react';
2	import { Pressable, type PressableProps, StyleSheet } from 'react-native';
3	import Animated, {
4	  useAnimatedStyle,
5	  useSharedValue,
6	  withSpring,
7	  type WithSpringConfig,
8	} from 'react-native-reanimated';
9	import * as Haptics from 'expo-haptics';
10	import { Plus } from 'lucide-react-native';
11	import { colors, shadows } from '@/design/tokens';
12	import { SPRING_SOFT, withReducedMotion } from '@/design/motion';
13	import { useReducedMotion } from '@/design/useReducedMotion';
14	
15	// Floating action button — docs/design.md §3.2 ("cta color, hard shadow, 56px")
16	// + §1.5 universal press-collapse via shadowOpacity / translate (same pattern as
17	// Button). Routes via the onPress callback; callers decide where it leads.
18	export type FabProps = {
19	  onPress: PressableProps['onPress'];
20	  accessibilityLabel: string;
21	  testID?: string;
22	};
23	
24	export function Fab({ onPress, accessibilityLabel, testID }: FabProps) {
25	  const reduced = useReducedMotion();
26	  const pressed = useSharedValue(0);
27	
28	  const animatedStyle = useAnimatedStyle(() => {
29	    const v = pressed.value;
30	    return {
31	      transform: [
32	        { translateX: v * 3 },
33	        { translateY: v * 3 },
34	        { scale: 1 - v * 0.03 },
35	      ],
36	      shadowOpacity: 1 - v,
37	    };
38	  });
39	
40	  const handlePressIn = useCallback(() => {
41	    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
42	    pressed.value = withSpring(1, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
43	  }, [pressed, reduced]);
44	
45	  const handlePressOut = useCallback(() => {
46	    pressed.value = withSpring(0, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
47	  }, [pressed, reduced]);
48	
49	  return (
50	    <Pressable
51	      onPress={onPress}
52	      onPressIn={handlePressIn}
53	      onPressOut={handlePressOut}
54	      accessibilityRole="button"
55	      accessibilityLabel={accessibilityLabel}
56	      testID={testID}
57	      style={styles.pressable}
58	    >
59	      <Animated.View style={[styles.fab, shadows.hard, animatedStyle]}>
60	        <Plus size={28} color={colors.ink} strokeWidth={2.5} />
61	      </Animated.View>
62	    </Pressable>
63	  );
64	}
65	
66	const styles = StyleSheet.create({
67	  pressable: {
68	    position: 'absolute',
69	    right: 20,
70	    bottom: 20,
71	  },
72	  fab: {
73	    width: 56,
74	    height: 56,
75	    borderRadius: 28,
76	    borderWidth: 2,
77	    borderColor: colors.ink,
78	    backgroundColor: colors.cta,
79	    alignItems: 'center',
80	    justifyContent: 'center',
81	  },
